public class Varargs {
    static int sum(int... nums) {
        int total = 0;
        for (int n : nums) total += n;
        return total;
    }
    public static void main(String[] args) {
        int[] data = {1, 2, 3};
        System.out.println(sum(data));   // bug: passes int[] not int...
    }
}
